#include<bits/stdc++.h>
using namespace std;

const int N=305;
long long w[N],s[N],f[N][N];

int main() {
    int n;
    cin>>n;

    for (int i=1;i<=n;i++) {
        cin >>w[i];
        s[i]=s[i-1]+w[i];
    }

    for (int len=2;len<=n;len++)
        for (int i=1;i+len-1<=n;i++) {
            int j=i+len-1;
            f[i][j]=1e18;
            for (int k=i;k<j;k++)
                f[i][j] = min(f[i][j], f[i][k]+f[k+1][j]+s[j]-s[i-1]);
        }

    cout <<f[1][n]<<endl;
    return 0;
}
